\tzpsection{Direct Equation Progression}
\begin{enumerate}[leftmargin=1.6em,itemsep=7pt,topsep=4pt]
\item \textbf{Canonical Relation}
\[
The inter-modal transfer rate \(T_{\mathrm{IM}}\) between two modes \(m_1, m_2\) of a field \(\phi\) is defined by \[ T_{\mathrm{IM}} \;=\; \frac{1}{u_T} \int_{\Sigma} \phi_{m_1}^* \, \mathcal{L} \, \phi_{m_2} \, \mathrm{d}\Sigma, \] where \(\mathcal{L}\) is the Trawinistic Lagrangian density and \(\Sigma\) is a hypersurface away from the TZP.\\
\]
This relation is retained from the source-repair evidence for Inter-Modal Transfer Rate.

\item \textbf{Support Relation}
\[
T_{\mathrm{IM}} \;=\; \frac{1}{u_T} \int_{\Sigma} \phi_{m_1}^* \, \mathcal{L} \, \phi_{m_2} \, \mathrm{d}\Sigma
\]
This relation is retained from the source-repair evidence for Inter-Modal Transfer Rate.

\item \textbf{Closure Relation}
\[
K_{\mathrm{NL}}=\frac{\lVert \nabla^{2}\varphi\rVert}{\lVert \nabla\varphi\rVert^{2}}
\]
This relation is retained from the source-repair evidence for Inter-Modal Transfer Rate.

\item \textbf{Auxiliary Relation}
\[
$\KNL$ is a dimensionless constant defined by the ratio $\KNL = \frac{\lVert \Nabla^2 \PhiField \rVert}{\lVert \Nabla \PhiField \rVert^2}$ evaluated in the limit as the field $\PhiField$ approaches the TZP, with $\Nabla$ denoting the Trawinistic connection.\\
\]
This relation is retained from the source-repair evidence for Inter-Modal Transfer Rate.

\item \textbf{Review Relation}
\[
\mathcal{L}_U = \frac{c^4}{16\pi G}\,R[g] \, + \, \mathcal{L}_{QFT}[\Psi, A_$\mu$] \, + \, \mathcal{L}_{topo}[A_$\mu$] \, + \, \mathcal{L}_{info}[\Phi] \, + \, \mathcal{L}_{bio}[\Xi].
\]
This relation is retained from the source-repair evidence for Inter-Modal Transfer Rate.

\end{enumerate}

